+func TestNewWorktreeService(t *testing.T) {
+	t.Parallel()
+
+	cfg := &config.Config{}
+	svc := NewWorktreeService(cfg)
+	if svc == nil {
+		t.Fatal("expected non-nil service")
+	}
+	if svc.managers == nil {
+		t.Fatal("expected managers map to be initialized")
+	}
+	if svc.config != cfg {
+		t.Fatal("expected config to be stored")
+	}
